const tg = $('📋 Preparar Payload').isExecuted;
const b64Raw = tg 
  ? $('📋 Preparar Payload').first().json.file_base64
  : $('✅ Validar Payload Entrante').first().json.file_base64;

const b64 = b64Raw.includes('base64,') 
  ? b64Raw.split('base64,').pop() 
  : b64Raw;

const supabase = $('🗄️ Obtener Config del Usuario (Supabase)').isExecuted;
const customPrompt = supabase
  ? ($('🗄️ Obtener Config del Usuario (Supabase)').first().json.prompt ?? null)
  : null;

const plan = $('✅ Validar Payload Entrante').isExecuted
  ? ($('✅ Validar Payload Entrante').first().json.plan ?? 'basic')
  : $('📋 Preparar Payload').isExecuted
    ? ($('📋 Preparar Payload').first()?.json?.plan ?? 'basic')
    : 'basic';

const promptGeneral = `Eres un experto en facturas dominicanas. Analiza la imagen y devuelve ÚNICAMENTE un JSON válido sin markdown ni explicaciones.

EMISOR vs CLIENTE — REGLA ABSOLUTA:
- EMISOR = negocio que vende. Siempre en el membrete/logo/encabezado superior.
- CLIENTE = quien compra. Aparece en "Nombre:", "A nombre de:", "Cliente:" dentro del cuerpo.
- NUNCA uses el mismo nombre para ambos.

NCF: Siempre B + 10 dígitos. Corrige "801"→"B01", "BO1"→"B01". Tipos: B01-B04, B11-B17.
RNC: Solo dígitos. 9 para empresas, 11 para personas.

Devuelve este JSON exacto:
{
  "emisor": "nombre del negocio emisor del membrete",
  "cliente": "nombre del cliente del cuerpo",
  "id_fiscal_emisor": "RNC emisor solo dígitos",
  "id_fiscal_cliente": "RNC cliente solo dígitos o N/A",
  "numero_factura": "número interno o N/A",
  "ncf": "NCF comenzando con B",
  "fecha_emision": "YYYY-MM-DD",
  "fecha_vencimiento": "YYYY-MM-DD o N/A",
  "subtotal": 0.00,
  "impuestos": 0.00,
  "total": 0.00,
  "moneda": "DOP",
  "concepto": "descripción breve general"
}`;

// Output 0: body limpio para mini OCR
// Output 1: metadatos para rama GPT-4o (b64 + plan)
return [
  {
    json: {
      model: "gpt-4o-mini",
      max_tokens: 800,
      messages: [{
        role: "user",
        content: [
          { type: "image_url", image_url: { url: `data:image/jpeg;base64,${b64}` }},
          { type: "text", text: customPrompt ?? promptGeneral }
        ]
      }]
    }
  },
  {
    json: {
      _b64: b64,
      _plan: plan
    }
  }
];

// Obtenemos la data del OCR validado y los metadatos iniciales
const invoice = $('⚙️ Normalizar + Validar NCF (DGII)').first().json.invoice;
const meta = $('✅ Validar Payload Entrante').first().json;

// Usamos la fecha detectada o la de hoy si falla
const rawDate = invoice.fecha_emision || new Date().toISOString().split('T')[0];

return [{
  json: {
    "user_id": meta.user_id,
    "request_id": meta.request_id || `REQ-${Date.now()}`,
    "Fecha de Factura (fecha)": rawDate,
    "Emisor": invoice.emisor || "Desconocido",
    "ID Fiscal (id_fiscal)": invoice.id_fiscal_emisor?.toString() || "",
    "factura": invoice.numero_factura || "",
    "ncf": invoice.ncf || "",
    "ITBIS": parseFloat(invoice.itbis || 0),
    "Total": parseFloat(invoice.total || 0),
    "Subtotal": parseFloat(invoice.subtotal || 0),
    "Concepto": invoice.concepto || "Otros",
    "Archivo de Factura (drive_file_id)": meta.drive_file_url || "",
    "Procesado en (procesado_en)": new Date().toISOString(),
    "status": "procesado",
    "rnc_empresa": meta.rnc_empresa,
    "tipo_fiscal": meta.tipo_fiscal || "606",
    "Detalle Articulos": JSON.stringify(invoice.detalle_articulos || [])
  }
}];

const supabaseResult = $('🔍 Buscar Usuario por Chat ID').first().json;
const userData = Array.isArray(supabaseResult) ? supabaseResult[0] : supabaseResult;

const b64Data = $('🔄 Convertir a Base64').first().json;

if (!userData || !userData.id) {
  throw new Error('Usuario no registrado. Tu Telegram Chat ID no está vinculado a ninguna cuenta Fluxia.');
}

return [{
  json: {
    user_id: userData.id,
    file_base64: b64Data.file_base64,
    file_name: b64Data.file_name,
    file_type: b64Data.file_type,
    audit_mode: false,
    _tg_source: true,
    _tg_chat_id: b64Data.chatId,
    request_id: `REQ-${Date.now()}-${userData.id.substring(0,8)}`  // ← línea nueva
  }
}];

const item = $input.first();
const binaryData = item.binary?.data;

if (!binaryData) throw new Error('No se encontró archivo binario');

const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64 = buffer.toString('base64');

const chatId = $('⬇️ Preparar Descarga').first().json.chatId;
const caption = $('⬇️ Preparar Descarga').first().json.caption ?? '';

return [{
  json: {
    chatId,
    caption,
    file_base64: `data:image/jpeg;base64,${base64}`,
    file_name: 'factura_telegram.jpg',
    file_type: 'jpg',
    audit_mode: false,
    _tg_source: true
  }
}];

const fileData = $input.first().json;
const chatId = $('✅ Validar Foto Telegram').first().json.chatId;
const userId = $('✅ Validar Foto Telegram').first().json.userId;
const caption = $('✅ Validar Foto Telegram').first().json.caption ?? '';

// Obtener el bot token de las credenciales no es directo en Code node
// Usamos el file_path del response anterior
const filePath = fileData.result?.file_path;
if (!filePath) throw new Error('No se pudo obtener el archivo de Telegram');

return [{
  json: {
    chatId,
    userId,
    caption,
    filePath,
    // file_base64 se construirá en el siguiente nodo HTTP
    _tg_source: true
  }
}];

const msg = $input.first().json.message ?? {};
const photo = msg.photo;
const document = msg.document;
const chatId = msg.chat?.id?.toString();
const userId = msg.from?.id?.toString();

if (!photo && !document) {
  // No es foto — responder al usuario
  return [{
    json: {
      _skip: true,
      chatId,
      errorMsg: '⚠️ Por favor envía una *foto* o imagen de tu factura.'
    }
  }];
}

// Obtener el file_id de la foto (mayor resolución)
const fileId = photo 
  ? photo[photo.length - 1].file_id 
  : document.file_id;

return [{
  json: {
    _skip: false,
    chatId,
    userId,
    fileId,
    caption: msg.caption ?? ''
  }
}];

// Convertir base64 a binario y preparar para Drive
const normalizar = $('⚙️ Normalizar + Validar NCF (DGII)').first().json;
const b64raw = $('🔄 Convertir Base64 a Binario').first().json.file_base64 
  ?? $('🔄 Convertir Base64 a Binario').first().json.archivo_base64 
  ?? '';
const clean = b64raw.includes(',') ? b64raw.split(',')[1] : b64raw;
const buf = Buffer.from(clean, 'base64');

const emisor = String(normalizar.invoice?.emisor ?? 'factura').replace(/[^a-zA-Z0-9]/g, '_');
const ncf    = String(normalizar.invoice?.ncf ?? 'sin_ncf').replace(/[^a-zA-Z0-9]/g, '_');
const fecha  = String(normalizar.invoice?.fecha_emision ?? '').replace(/\//g, '-');
const filename = `${emisor}_${ncf}_${fecha}.jpg`;

return [{
  json: { ...normalizar, _filename: filename },
  binary: {
    data: await this.helpers.prepareBinaryData(buf, filename, 'image/jpeg')
  }
}];

const input = $input.first().json;
const b64 = (input.file_base64 ?? input.archivo_base64 ?? '');
const clean = b64.includes(',') ? b64.split(',')[1] : b64;

return [{
  json: { ...input },
  binary: {
    data: {
      data: clean,
      mimeType: 'image/jpeg',
      fileName: 'factura.jpg',
      fileExtension: 'jpg'
    }
  }
}];

const body = $input.first().json.body ?? $input.first().json;
const userId = body.user_id ?? null;
const mes = String(body.mes || '03').padStart(2, '0');
const anio = String(body.anio || '2026');

if (!userId) throw new Error('DEBES ESTAR LOGUEADO (MISSING_USER_ID)');

// Enviamos todo lo que viene de la App + los datos formateados
return [{ 
  json: { 
    ...body, 
    user_id: userId, 
    mes, 
    anio, 
    periodo: `${anio}${mes}` 
  } 
}];

// Captura errores de cualquier nodo y los formatea
const error = $input.first();
const msg = error?.json?.message ?? error?.json?.error ?? 'Error desconocido';
const code = msg.includes(':') ? msg.split(':')[0].trim() : 'PROCESSING_ERROR';

return [{
  json: {
    status: 'error',
    error_code: code,
    message: msg,
    timestamp: new Date().toISOString()
  }
}];

// ── Normalización Multi-Tenant + Validación NCF DGII ─────
const rawContent  = $input.first()?.json?.choices?.[0]?.message?.content ?? $input.first()?.json?.content ?? '{}';
const ctx = $('🔍 ¿Usuario existe y tiene créditos?').isExecuted
  ? $('🔍 ¿Usuario existe y tiene créditos?').first().json
  : { user_id: $('📋 Preparar Payload').first().json.user_id, config: {}, request_id: null };
const userId      = ctx.user_id;
const config      = ctx.config;
const requestId = ctx.request_id 
  ?? $('📋 Preparar Payload').first()?.json?.request_id 
  ?? null;

let invoiceData = {};

// ── Helper: limpiar número ─────────────────────────────────
const toFloat = (text) => {
  if (typeof text === 'number') return text;
  if (!text || text === 'N/A') return 0;
  return parseFloat(String(text).replace(/[^0-9.]+/g, '')) || 0;
};

// ── Helper: formatear moneda ───────────────────────────────
const fmt = (n) => new Intl.NumberFormat('es-DO', {
  minimumFractionDigits: 2,
  maximumFractionDigits: 2
}).format(n);

// ── Helper: parsear fecha a YYYY-MM-DD ────────────────────
const meses = {
  'enero':1,'febrero':2,'marzo':3,'abril':4,'mayo':5,'junio':6,
  'julio':7,'agosto':8,'septiembre':9,'octubre':10,'noviembre':11,'diciembre':12
};

const parseFecha = (f) => {
  if (!f || f === 'N/A') return null;
  if (/^\d{4}-\d{2}-\d{2}$/.test(f)) return f;
  const slash = f.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/);
  if (slash) {
    return `${slash[3]}-${slash[2].padStart(2,'0')}-${slash[1].padStart(2,'0')}`;
  }
  const esp = f.toLowerCase().match(/(\d{1,2})\s+([a-záéíóúü]+)\s+(\d{4})/);
  if (esp) {
    const d = esp[1].padStart(2,'0');
    const mes = String(meses[esp[2]] || 1).padStart(2,'0');
    return `${esp[3]}-${mes}-${d}`;
  }
  const d = new Date(f);
  return isNaN(d) ? null : d.toISOString().split('T')[0];
};

// ── Auto-corrección de errores OCR en NCF ─────────────────
const corregirNCF = (ncf) => {
  if (!ncf || ncf === 'N/A') return ncf;
  let s = String(ncf).trim().toUpperCase().replace(/\s/g, '');

  // Eliminar guiones o puntos internos: B01-00001234 → B0100001234
  s = s.replace(/[-\.]/g, '');

  // Error más común: 8 o O en lugar de B al inicio
  // 801XXXXXXXX → B01XXXXXXXX
  if (/^[8O]\d{10}$/.test(s)) {
    s = 'B' + s.slice(1);
  }

  // BO1 → B01 (letra O confundida con cero)
  s = s.replace(/^BO(\d)/, 'B0$1');

  // B0l → B01 (l minúscula confundida con 1)
  s = s.replace(/^(B\d)l/, '$11');

  // Quitar prefijo "NCF:" o "NCF " si el modelo lo incluyó
  s = s.replace(/^NCF[:\s]*/i, '');

  return s;
};

// ── Validar estructura NCF dominicano ─────────────────────
const validarNCF = (ncf) => {
  if (!ncf || ncf === 'N/A') return { valid: false, tipo: null, motivo: 'NCF ausente' };

  const tipos = {
    'B01': 'Crédito Fiscal',
    'B02': 'Consumidor Final',
    'B03': 'Nota de Débito',
    'B04': 'Nota de Crédito',
    'B11': 'Proveedores Informales',
    'B12': 'Único Ingreso',
    'B13': 'Gastos Menores',
    'B14': 'Regímenes Especiales',
    'B15': 'Gubernamental',
    'B16': 'Exportaciones',
    'B17': 'Pagos al Exterior'
  };

  const ncfUpper = String(ncf).toUpperCase().replace(/\s/g, '');
  const match = ncfUpper.match(/^(B\d{2})(\d{8})$/);

  if (!match) {
    return { valid: false, tipo: null, motivo: `Formato inválido: '${ncf}'. Esperado: B01XXXXXXXX` };
  }

  const codigo = match[1];
  const secuencia = match[2];
  const tipoNombre = tipos[codigo];

  if (!tipoNombre) {
    return { valid: false, tipo: codigo, motivo: `Código NCF '${codigo}' no reconocido por DGII` };
  }

  if (secuencia === '00000000') {
    return { valid: false, tipo: codigo, motivo: 'Secuencia NCF inválida (todos ceros)' };
  }

  return {
    valid: true,
    tipo: codigo,
    tipo_nombre: tipoNombre,
    ncf_normalizado: `${codigo}${secuencia}`,
    motivo: null
  };
};

// ── Parsear JSON de la IA ──────────────────────────────────
try {
  const jsonMatch = rawContent.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('La IA no devolvió un JSON válido.');
  invoiceData = JSON.parse(jsonMatch[0]);
} catch(e) {
  return [{
    json: {
      status: 'error',
      error_code: 'OCR_PARSE_ERROR',
      error_message: e.message,
      user_id: userId,
      request_id: requestId
    }
  }];
}

// ── Normalizar campos ─────────────────────────────────────
const fields = ['emisor','cliente','id_fiscal_emisor','id_fiscal_cliente',
  'numero_factura','ncf','fecha_emision','fecha_vencimiento','moneda','concepto'];
for (const f of fields) {
  invoiceData[f] = invoiceData[f] || 'N/A';
}

// ── Aplicar auto-corrección OCR al NCF ────────────────────
invoiceData.ncf = corregirNCF(invoiceData.ncf);

const subtotal = toFloat(invoiceData.subtotal);
const itbis    = toFloat(invoiceData.impuestos);
const total    = toFloat(invoiceData.total);

// ── Parsear fechas a formato Airtable (YYYY-MM-DD) ────────
const fechaEmision     = parseFecha(invoiceData.fecha_emision);
const fechaVencimiento = parseFecha(invoiceData.fecha_vencimiento);

// ── Validar NCF (ya corregido) ────────────────────────────
const ncfValidation = validarNCF(invoiceData.ncf);

// ── Mensaje Telegram enriquecido ─────────────────────────
const estadoNCF = ncfValidation.valid
  ? `✅ Válido — ${ncfValidation.tipo_nombre}`
  : `❌ Inválido — ${ncfValidation.motivo}`;

const telegramMessage = [
  `🧾 <b>Factura Procesada</b>`,
  `<code>ID: ${requestId}</code>`,
  ``,
  `🏢 <b>Emisor:</b> ${invoiceData.emisor}`,
  `🪪 <b>RNC:</b> <code>${invoiceData.id_fiscal_emisor}</code>`,
  ``,
  `🔢 <b>Factura #:</b> <code>${invoiceData.numero_factura}</code>`,
  `📋 <b>NCF:</b> <code>${invoiceData.ncf}</code> — ${estadoNCF}`,
  `📅 <b>Fecha:</b> ${invoiceData.fecha_emision}`,
  ``,
  `💵 Subtotal: ${fmt(subtotal)} ${invoiceData.moneda}`,
  `💸 ITBIS: ${fmt(itbis)} ${invoiceData.moneda}`,
  `<b>✅ Total: ${fmt(total)} ${invoiceData.moneda}</b>`,
  ``,
  `📝 ${invoiceData.concepto}`
].join('\n');

return [{
  json: {
    status: 'ok',
    user_id: userId,
    request_id: requestId,
    folder_drive_id:   config?.folder_drive_id   ?? null,
    airtable_base_id:  config?.airtable_base_id  ?? 'appPfkS3Gi2CJEDuG',
    airtable_table_id: config?.airtable_table_id ?? 'tbl7XkZpew0ZU64rG',
    telegram_chat_id:  config?.telegram_chat_id  ?? null,
    invoice: {
      emisor:             invoiceData.emisor,
      cliente:            invoiceData.cliente,
      id_fiscal_emisor:   invoiceData.id_fiscal_emisor,
      id_fiscal_cliente:  invoiceData.id_fiscal_cliente,
      numero_factura:     invoiceData.numero_factura,
      ncf:                invoiceData.ncf,
      ncf_validacion:     ncfValidation,
      fecha_emision:      fechaEmision,
      fecha_vencimiento:  fechaVencimiento,
      subtotal,
      itbis,
      total,
      moneda:             invoiceData.moneda,
      concepto:           invoiceData.concepto,
      detalle_articulos:  Array.isArray(invoiceData.detalle_articulos) ? invoiceData.detalle_articulos : [],
      ocr_raw:            rawContent
    },
    telegramMessage
  }
}];

// ── Verificar que el usuario existe y tiene créditos ─────
const prevData    = $('✅ Validar Payload Entrante').first().json;
const configArray = $input.all();

if (!configArray || configArray.length === 0 || !configArray[0].json.user_id) {
  throw new Error(`USER_NOT_FOUND: No se encontró configuración para user_id='${prevData.user_id}'`);
}

const config = configArray[0].json;

// Verificar créditos
const usados = config.creditos_usados ?? 0;
const limite = config.creditos_limite ?? 100;

if (usados >= limite) {
  throw new Error(`CREDITS_EXHAUSTED: El usuario '${config.user_id}' ha alcanzado su límite de ${limite} créditos. Usados: ${usados}.`);
}

// Pasar todo el contexto enriquecido al siguiente nodo
return [{
  json: {
    ...prevData,
    config: {
      user_id:           config.user_id,
      plan:              config.plan,
      creditos_usados:   usados,
      creditos_limite:   limite,
      folder_drive_id:   config.folder_drive_id,
      spreadsheet_id:    config.spreadsheet_id,
      airtable_base_id:  config.airtable_base_id,
      airtable_table_id: config.airtable_table_id,
      telegram_chat_id:  config.telegram_chat_id,
      whatsapp_number:   config.whatsapp_number,
      notif_canal:       config.notif_canal ?? 'telegram',
      prompt:            config.prompt_personalizado ?? null
    }
  }
}];

// ── Validación de entrada Multi-Tenant & Multi-Acción ──────────────────
const body = $input.first().json.body ?? $input.first().json;

// Detectamos la acción (si no viene, asumimos que es procesar factura)
const action   = body.action    ?? 'process_invoice'; 
const userId   = body.user_id   ?? body.userId   ?? null;

if (!userId) throw new Error('MISSING_USER_ID: El campo user_id es obligatorio.');

// --- CASO 1: CREACIÓN DE CARPETA DE CLIENTE ---
if (action === 'create_client_folder') {
  return [{
    json: {
      action,
      user_id: userId,
      client_name: body.client_name ?? 'Sin Nombre',
      root_folder_id: body.root_folder_id ?? null,
      request_id: `REQ-FOLDER-${Date.now()}`
    }
  }];
}

// --- CASO 2: PROCESAMIENTO ESTÁNDAR DE FACTURA ---
const fileB64  = body.file_base64 ?? body.fileBase64 ?? null;
const fileName = body.file_name   ?? body.fileName ?? 'factura.jpg';
const auditMode = body.audit_mode ?? false;
const rncEmpresa = body.rnc_empresa ?? '';
const targetFolder = body.drive_folder_id ?? ''; 

if (!fileB64) throw new Error('MISSING_FILE: No se recibió ningún archivo (file_base64).');

const ext = fileName.split('.').pop().toLowerCase();
const allowedTypes = ['jpg', 'jpeg', 'png', 'pdf', 'webp'];
if (!allowedTypes.includes(ext)) {
  throw new Error(`INVALID_TYPE: Tipo '${ext}' no soportado.`);
}

const cleanBase64 = fileB64.replace(/^data:[^;]+;base64,/, '');

return [{
  json: {
    action,
    user_id: userId,
    file_base64: cleanBase64,
    file_name: fileName,
    file_type: ext,
    audit_mode: auditMode,
    rnc_empresa: rncEmpresa,
    tipo_fiscal: body.tipo_fiscal ?? '606', // <--- CAPTURA EL TIPO 606/607
    drive_folder_id: targetFolder, 
    received_at: new Date().toISOString(),
    request_id: `REQ-${Date.now()}-${userId.substring(0,8)}`
  }
}];

// 1. Acceso a datos
const data = $input.first()?.json || {};
const invoices = data.invoices || [];
const rnc = data.rncEmpresa || "101863567";
const period = data.periodo || "202603";

const headers = ["RNC o Cédula", "Tipo Id", "Bienes/Servicios", "NCF", "NCF Modificado", "Fecha Comp.", "Fecha Pago", "M. Serv", "M. Bien", "Total", "ITBIS", "Ret.", "Prop. Itbis", "Costo", "Adelanto", "Perc compras", "T. Ret ISR", "Ret Renta", "Perc ISR", "ISC", "Otros", "Propina", "Pago"];

// 2. Generar Filas (con &nbsp; para evitar error de números científicos)
const rows = invoices.map(inv => {
  const rncC = String(inv.rnc || "").replace(/\D/g, "");
  const ncfC = String(inv.ncf || "").replace(/\s/g, "");
  const m = parseFloat(String(inv.monto || "0").replace(/[^0-9.]/g, "")) || 0;
  const i = parseFloat(String(inv.itbis || "0").replace(/[^0-9.]/g, "")) || 0;
  let f = String(inv.fecha || "").replace(/\D/g, "").substring(0,8) || period + "01";

  return `<tr>
    <td>&nbsp;${rncC}</td>
    <td style='text-align:center'>${rncC.length===11?2:1}</td>
    <td style='text-align:center'>02</td>
    <td>${ncfC}</td>
    <td></td>
    <td style='text-align:center'>&nbsp;${f}</td>
    <td style='text-align:center'>&nbsp;${f}</td>
    <td style='text-align:right'>${m.toFixed(2)}</td>
    <td>0.00</td>
    <td style='text-align:right'>${m.toFixed(2)}</td>
    <td style='text-align:right'>${i.toFixed(2)}</td>
    <td style='text-align:right'>0.00</td>
    <td style='text-align:right'>0.00</td>
    <td style='text-align:right'>0.00</td>
    <td style='text-align:right'>${i.toFixed(2)}</td>
    <td style='text-align:right'>0.00</td>
    <td></td>
