// Verificar firma HMAC-SHA256
const signature = headers['whop-signature'] ?? headers['x-whop-signature'] ?? null;
const rawBody = typeof body === 'string' ? body : JSON.stringify(body);

if (signature) {
  const expectedSig = crypto
    .createHmac('sha256', WHOP_SECRET)
    .update(rawBody)
    .digest('hex');

  if (signature !== expectedSig && !signature.includes(expectedSig)) {
    throw new Error('INVALID_WHOP_SIGNATURE: Firma del webhook no válida.');
  }
}

// Parsear body si viene como string
const event = typeof body === 'string' ? JSON.parse(body) : body;
const eventType = event.action ?? event.type ?? null;

